def get_icono(key, color="currentColor", size=18):
    """Devuelve el SVG de un ícono ya listo para insertar con st.markdown.
    Si la key no existe, devuelve un ícono genérico de placeholder."""
    svg = ICONOS.get(key, ICONOS["dashboard"])
    svg = svg.replace('width="18"', f'width="{size}"').replace('height="18"', f'height="{size}"')
    return svg